const b = $json.body || $json;
const clean = (v) => (v ?? '').toString().trim();
const matter = clean(b.matter_type).toLowerCase() || 'otro';
const priorityRaw = clean(b.priority).toLowerCase();
const allowedPriority = ['baja','media','alta','critica'];
const priority = allowedPriority.includes(priorityRaw) ? priorityRaw : 'media';
const summary = clean(b.summary || b.text || '');
const hasContact = clean(b.phone) !== '' || clean(b.email) !== '';
const consent = b.consent_data_processing === true;
const valid = clean(b.full_name) !== '' && hasContact && consent && summary !== '';
return [{
  json: {
    valid,
    error: valid ? '' : 'Campos requeridos: full_name, (phone o email), consentimiento=true y summary/text',
    full_name: clean(b.full_name),
    phone: clean(b.phone),
    email: clean(b.email),
    preferred_channel: clean(b.preferred_channel) || 'whatsapp',
    matter_type: matter,
    priority,
    summary,
    source_channel: clean(b.source_channel) || 'whatsapp'
  }
}];

